import type { Metadata } from "next";
import { Geist, Geist_Mono } from "next/font/google";
import "./globals.css";
import { Toaster } from "@/components/ui/toaster";

const geistSans = Geist({
  variable: "--font-geist-sans",
  subsets: ["latin"],
});

const geistMono = Geist_Mono({
  variable: "--font-geist-mono",
  subsets: ["latin"],
});

export const metadata: Metadata = {
  title: "TenshiTV Catalogue - Streaming d'Animes HD en VF et VOSTFR",
  description: "Explorez le catalogue complet de TenshiTV. Tous les animes en streaming HD gratuit avec épisodes VF et VOSTFR. Nouveautés, classiques, films d'animation et plus encore.",
  keywords: ["anime", "streaming", "VF", "VOSTFR", "manga", "animation", "HD", "gratuit", "séries", "films", "tenshitv", "catalogue"],
  authors: [{ name: "TenshiTV Catalogue" }],
  icons: {
    icon: "/logo.svg",
  },
  openGraph: {
    title: "TenshiTV Catalogue - Streaming d'Animes HD",
    description: "Explorez le catalogue complet de TenshiTV avec tous les animes en streaming HD",
    siteName: "TenshiTV Catalogue",
    type: "website",
  },
  twitter: {
    card: "summary_large_image",
    title: "TenshiTV Catalogue - Streaming d'Animes HD",
    description: "Explorez le catalogue complet de TenshiTV avec tous les animes en streaming HD",
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="fr" suppressHydrationWarning>
      <body
        className={`${geistSans.variable} ${geistMono.variable} antialiased bg-gray-950 text-white`}
      >
        {children}
        <Toaster />
      </body>
    </html>
  );
}

