'use client';

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { AnimeDetail } from '@/components/anime/AnimeDetail';
import { AnimeGrid } from '@/components/anime/AnimeGrid';
import type { AnimeDetail as AnimeDetailType } from '@/types/anime';

export default function AnimePage() {
  const params = useParams();
  const router = useRouter();
  const slug = params?.slug as string;

  const [anime, setAnime] = useState<AnimeDetailType | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!slug) return;

    const fetchAnime = async () => {
      setLoading(true);
      setError(null);

      try {
        const response = await fetch(`/api/animes/${slug}`);

        if (!response.ok) {
          throw new Error('Anime non trouvé');
        }

        const data = await response.json();
        setAnime(data);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Erreur lors du chargement');
      } finally {
        setLoading(false);
      }
    };

    fetchAnime();
  }, [slug]);

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0B0A12] text-white">
        <div className="flex items-center justify-center min-h-[60vh]">
          <div className="text-center">
            <div className="w-16 h-16 border-4 border-purple-500 border-t-transparent rounded-full animate-spin mx-auto mb-4" />
            <p className="text-gray-400">Chargement...</p>
          </div>
        </div>
      </div>
    );
  }

  if (error || !anime) {
    return (
      <div className="min-h-screen bg-[#0B0A12] text-white">
        <div className="flex items-center justify-center min-h-[60vh]">
          <div className="text-center">
            <div className="w-20 h-20 rounded-full bg-red-500/20 flex items-center justify-center mx-auto mb-4">
              <svg className="w-10 h-10 text-red-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </div>
            <h2 className="text-xl font-bold mb-2">{error || 'Anime non trouvé'}</h2>
            <button
              onClick={() => router.push('/')}
              className="text-purple-400 hover:text-purple-300 transition-colors"
            >
              ← Retour au catalogue
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0B0A12] text-white">
      <AnimeDetail anime={anime} />

      {/* Back button */}
      <div className="px-4 md:px-8 lg:px-16 py-8">
        <button
          onClick={() => router.push('/')}
          className="text-purple-400 hover:text-purple-300 transition-colors flex items-center gap-2"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
          Retour au catalogue
        </button>
      </div>

      {/* Similar animes section */}
      {anime.similar && anime.similar.length > 0 && (
        <div className="px-4 md:px-8 lg:px-16 pb-12">
          <AnimeGrid animes={anime.similar} title="Animes similaires" />
        </div>
      )}

      {/* Footer */}
      <footer className="border-t border-white/5 mt-auto">
        <div className="px-4 md:px-8 lg:px-16 py-6">
          <div className="flex flex-col md:flex-row items-center justify-between gap-4">
            <p className="text-gray-500 text-sm">
              Données fournies par TenshiTV API
            </p>
            <p className="text-gray-600 text-xs">
              Ce site est un projet de démonstration
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
}

src/app/watch/[slug]/[season]/[episode]/.content:
'use client';

import { useState, useEffect } from 'react';
import { useParams } from 'next/navigation';
import { motion } from 'framer-motion';
import { ArrowLeft, AlertCircle, ExternalLink, Loader2, Play } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import Link from 'next/link';

export default function WatchPage() {
  const params = useParams();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [animeTitle, setAnimeTitle] = useState<string>('');
  const [animeData, setAnimeData] = useState<{
    title: string;
    slug: string;
    coverImage: string | null;
  } | null>(null);

  const slug = params.slug as string;
  const season = decodeURIComponent(params.season as string);
  const episode = params.episode as string;
  const language = params.language as string;

  useEffect(() => {
    async function fetchEpisode() {
      try {
        setLoading(true);

        // Fetch anime details to get the external ID
        const animeRes = await fetch(`/api/anime/${slug}`);
        const animeData = await animeRes.json();

        if (!animeData.success) {
          throw new Error('Anime non trouvé');
        }

        setAnimeTitle(animeData.data.title);
        setAnimeData({
          title: animeData.data.title,
          slug: animeData.data.slug,
          coverImage: animeData.data.coverImage,
        });

        // Get the external ID from the anime data
        const externalId = animeData.data.externalId;

        if (!externalId) {
          throw new Error('ID externe non trouvé');
        }

        // Fetch episodes via our proxy API
        const episodesRes = await fetch(`/api/episodes/${externalId}`);
        const episodesData = await episodesRes.json();

        if (!episodesData.success) {
          throw new Error('Impossible de charger les épisodes');
        }

        const episodes = episodesData.data;

        // Find the matching episode
        const ep = episodes.find((e: { 
          season_label: string; 
          episode_number: number; 
          language: string;
          video_url: string;
        }) => 
          e.season_label === season && 
          e.episode_number === parseInt(episode) && 
          e.language === language
        );

        if (ep && ep.video_url) {
          setVideoUrl(ep.video_url);
        } else {
          // Try to find any episode with the same number and different language
          const altEp = episodes.find((e: { 
            season_label: string; 
            episode_number: number;
            video_url: string;
          }) => 
            e.season_label === season && 
            e.episode_number === parseInt(episode)
          );

          if (altEp && altEp.video_url) {
            setVideoUrl(altEp.video_url);
          } else {
            throw new Error('Épisode non trouvé');
          }
        }
      } catch (err) {
        console.error('Error fetching episode:', err);
        setError(err instanceof Error ? err.message : 'Erreur lors du chargement');
      } finally {
        setLoading(false);
      }
    }

    fetchEpisode();
  }, [slug, season, episode, language]);

  const openInNewTab = () => {
    if (videoUrl) {
      window.open(videoUrl, '_blank');
    }
  };

  const openOnTenshiTV = () => {
    window.open(`https://tenshitv.com/anime/${slug}`, '_blank');
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center">
        <div className="text-center space-y-4">
          <Loader2 className="w-12 h-12 text-purple-500 animate-spin mx-auto" />
          <p className="text-gray-400">Chargement de la vidéo...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center p-4">
        <div className="text-center space-y-6 max-w-md">
          <AlertCircle className="w-16 h-16 text-amber-500 mx-auto" />
          <h1 className="text-2xl font-bold text-white">Oups!</h1>
          <p className="text-gray-400">{error}</p>
          <div className="flex flex-col gap-3">
            <Button onClick={openOnTenshiTV} className="bg-purple-600 hover:bg-purple-500">
              <ExternalLink className="w-4 h-4 mr-2" />
              Voir sur TenshiTV
            </Button>
            <Link href="/">
              <Button variant="outline" className="w-full border-white/20 text-white hover:bg-white/5">
                <ArrowLeft className="w-4 h-4 mr-2" />
                Retour au catalogue
              </Button>
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-950 text-white">
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-50 bg-gray-950/95 backdrop-blur-sm border-b border-white/10">
        <div className="px-4 py-3 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Link href="/">
              <Button variant="ghost" size="sm" className="text-gray-400 hover:text-white">
                <ArrowLeft className="w-4 h-4 mr-2" />
                Retour
              </Button>
            </Link>
            <div className="flex items-center gap-3">
              {animeData?.coverImage && (
                <img 
                  src={animeData.coverImage} 
                  alt={animeTitle}
                  className="w-10 h-14 object-cover rounded"
                />
              )}
              <div>
                <h1 className="font-semibold text-white truncate max-w-[150px] sm:max-w-[300px] md:max-w-none">
                  {animeTitle}
                </h1>
                <div className="flex items-center gap-2 text-sm text-gray-400">
                  <span>{season}</span>
                  <span>•</span>
                  <span>Épisode {episode}</span>
                  <span>•</span>
                  <Badge variant="outline" className="text-xs border-purple-500/30 text-purple-300">
                    {language === 'VF' ? '🇫🇷 VF' : '🇯🇵 VOSTFR'}
                  </Badge>
                </div>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <Button 
              onClick={openInNewTab}
              variant="outline" 
              size="sm"
              className="border-white/20 text-gray-300 hover:text-white hidden sm:flex"
            >
              <ExternalLink className="w-4 h-4 mr-2" />
              Lecteur externe
            </Button>
            <Button 
              onClick={openOnTenshiTV}
              className="bg-purple-600 hover:bg-purple-500"
              size="sm"
            >
              TenshiTV
            </Button>
          </div>
        </div>
      </header>

      {/* Video Player */}
      <main className="pt-16 min-h-screen flex items-center justify-center bg-black">
        <div className="w-full h-[calc(100vh-4rem)] relative">
          {videoUrl ? (
            <motion.iframe
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.3 }}
              src={videoUrl}
              className="w-full h-full border-0"
              allowFullScreen
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; fullscreen"
            />
          ) : (
            <div className="flex items-center justify-center h-full">
              <p className="text-gray-400">Aucune vidéo disponible</p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
